#include <stdio.h>

void unesi(char niz[], int velicina) {
	char znak = getchar();
	if (znak == '\n') znak = getchar();
	int i = 0;
	while (i < velicina-1 && znak != '\n') {
		niz[i] = znak;
		i++;
		znak = getchar();
	}
	niz[i] = '\0';
}

int main() {
    char ime[20], prezime[20];
	int brindeksa;
	
	printf ("Unesite broj indeksa: ");
	scanf ("%d", &brindeksa);
	printf ("Unesite ime: ");
	unesi(ime, 20);
	printf ("Unesite prezime: ");
	unesi(prezime, 20);

    return 0;
}
